from __future__ import annotations

import asyncio
import inspect
import json
import secrets
import threading
from collections.abc import Mapping
from dataclasses import dataclass
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer
from typing import Any
from ._local_store import (
    LocalAgentStoreHandler,
    dispatch_store_op,
    is_local_agent_store_handler,
)
from .errors import ConfigurationError, CursorSDKError
from .types import LocalAgentOptions, _normalize_local_options

STORE_CALLBACK_SERVICE = "sdk.v1.SdkStoreCallbackService"
CONNECT_PROTOCOL_VERSION = "1"

__all__ = [
    "LocalAgentStoreHandler",
    "StoreCallbackEndpoint",
    "StoreCallbackServer",
]


@dataclass(frozen=True)
class StoreCallbackEndpoint:
    url: str
    auth_token: str


class StoreCallbackServer:
    """Loopback Connect/JSON server for ``SdkStoreCallbackService``.

    Hosts a ``LocalAgentStoreHandler`` (the ``agents``/``runs``/``run_events``/
    ``checkpoints`` substores, mirroring ``@cursor/sdk``'s ``LocalAgentStore``)
    so the Node bridge can forward store operations over the generic
    ``CallStore`` RPC. Used by ``local.store`` type ``"custom"`` (fully
    host-owned).

    Pass ``loop`` (the caller's running event loop) to support ``async``
    substore methods: requests arrive on the threaded HTTP server and any
    returned coroutine is run on ``loop`` via ``run_coroutine_threadsafe``.
    """

    def __init__(
        self,
        handler: LocalAgentStoreHandler,
        *,
        host: str = "127.0.0.1",
        port: int = 0,
        auth_token: str | None = None,
        loop: asyncio.AbstractEventLoop | None = None,
    ) -> None:
        if not is_local_agent_store_handler(handler):
            raise ConfigurationError(
                "store handler must be a LocalAgentStoreHandler implementing "
                "agents/runs/run_events/checkpoints."
            )
        self._handler = handler
        self._auth_token = auth_token or _new_auth_token()
        self._httpd = ThreadingHTTPServer(
            (host, port),
            _make_request_handler(self._handler, self._auth_token, loop),
        )
        self._httpd.daemon_threads = True
        # Serve in the background so the bridge subprocess can call back as
        # soon as the endpoint is handed to it.
        self._serve_thread = threading.Thread(
            target=self._httpd.serve_forever, daemon=True
        )
        self._serve_thread.start()

    @property
    def endpoint(self) -> StoreCallbackEndpoint:
        host, port = self._httpd.server_address
        if isinstance(host, bytes):
            host = host.decode("utf-8")
        if ":" in host and not host.startswith("["):
            host = f"[{host}]"
        return StoreCallbackEndpoint(
            url=f"http://{host}:{port}/",
            auth_token=self._auth_token,
        )

    def close(self) -> None:
        # `shutdown()` must run off the request thread when using
        # `ThreadingHTTPServer`; join with a timeout so tests and bridge
        # teardown do not hang if a stray client keeps a worker busy.
        shutdown_thread = threading.Thread(target=self._httpd.shutdown, daemon=True)
        shutdown_thread.start()
        shutdown_thread.join(timeout=5)
        self._serve_thread.join(timeout=5)
        self._httpd.server_close()

    def __enter__(self) -> "StoreCallbackServer":
        return self

    def __exit__(self, exc_type: object, exc: object, tb: object) -> None:
        self.close()


class _BodyFramingError(Exception):
    """Raised for a malformed Content-Length or chunked request body."""


def _new_auth_token() -> str:
    return secrets.token_urlsafe(32)


def _make_request_handler(
    store_handler: LocalAgentStoreHandler,
    auth_token: str,
    loop: asyncio.AbstractEventLoop | None,
) -> type[BaseHTTPRequestHandler]:
    class Handler(BaseHTTPRequestHandler):
        def log_message(self, format: str, *args: Any) -> None:
            return

        def do_POST(self) -> None:
            if not self.path.startswith("/"):
                self._write_error(404, "not_found", "Unknown path")
                return
            path = self.path.lstrip("/")
            if path.count("/") != 1:
                self._write_error(404, "not_found", "Unknown path")
                return
            service, method = path.split("/", 1)
            if service != STORE_CALLBACK_SERVICE:
                self._write_error(404, "not_found", "Unknown service")
                return
            if not self._authorized():
                self._write_error(401, "unauthenticated", "Unauthorized")
                return
            if self.headers.get("Connect-Protocol-Version") != CONNECT_PROTOCOL_VERSION:
                self._write_error(
                    400, "invalid_argument", "Unsupported Connect version"
                )
                return
            try:
                raw = self._read_body()
            except _BodyFramingError:
                self._write_error(
                    400, "invalid_argument", "Invalid request body framing"
                )
                return
            try:
                request = json.loads((raw or b"{}").decode("utf-8"))
            except json.JSONDecodeError:
                self._write_error(400, "invalid_argument", "Invalid JSON body")
                return
            if not isinstance(request, Mapping):
                self._write_error(400, "invalid_argument", "Expected JSON object")
                return
            try:
                response = _dispatch(store_handler, method, request, loop)
            except CursorSDKError as error:
                self._write_error(400, "invalid_argument", str(error))
                return
            except Exception as error:
                self._write_error(500, "internal", str(error))
                return
            body = json.dumps(response).encode("utf-8")
            self.send_response(200)
            self.send_header("Content-Type", "application/json")
            self.send_header("Connect-Protocol-Version", CONNECT_PROTOCOL_VERSION)
            self.send_header("Content-Length", str(len(body)))
            self.end_headers()
            self.wfile.write(body)

        def _read_body(self) -> bytes:
            # Connect clients (e.g. connect-node) send unary request bodies with
            # chunked transfer-encoding and no Content-Length, so handle both.
            encoding = self.headers.get("Transfer-Encoding", "")
            if "chunked" in encoding.lower():
                return self._read_chunked_body()
            try:
                length = int(self.headers.get("Content-Length", "0"))
            except ValueError as error:
                raise _BodyFramingError from error
            if length < 0:
                raise _BodyFramingError
            return self._read_exact(length) if length > 0 else b""

        def _read_exact(self, size: int) -> bytes:
            # rfile.read(n) can return fewer than n bytes; loop until satisfied.
            buf = bytearray()
            while len(buf) < size:
                chunk = self.rfile.read(size - len(buf))
                if not chunk:
                    raise _BodyFramingError  # connection closed mid-body
                buf += chunk
            return bytes(buf)

        def _read_chunked_body(self) -> bytes:
            body = bytearray()
            while True:
                size_token = self.rfile.readline().split(b";", 1)[0].strip()
                try:
                    size = int(size_token, 16)
                except ValueError as error:
                    raise _BodyFramingError from error
                if size == 0:
                    while self.rfile.readline().strip():  # consume trailers
                        pass
                    return bytes(body)
                body += self._read_exact(size)
                self._read_exact(2)  # trailing CRLF

        def _authorized(self) -> bool:
            authorization = self.headers.get("Authorization", "")
            if not authorization.startswith("Bearer "):
                return False
            bearer = authorization[len("Bearer ") :]
            return secrets.compare_digest(bearer, auth_token)

        def _write_error(self, status: int, code: str, message: str) -> None:
            payload = {"code": code, "message": message}
            body = json.dumps(payload).encode("utf-8")
            self.send_response(status)
            self.send_header("Content-Type", "application/json")
            self.send_header("Connect-Protocol-Version", CONNECT_PROTOCOL_VERSION)
            self.send_header("Content-Length", str(len(body)))
            self.end_headers()
            self.wfile.write(body)

    return Handler


def _dispatch(
    store_handler: LocalAgentStoreHandler,
    method: str,
    request: Mapping[str, Any],
    loop: asyncio.AbstractEventLoop | None,
) -> dict[str, Any]:
    if method != "CallStore":
        raise CursorSDKError(f"Unknown method: {method}")
    substore = _require_string(request, "substore")
    op = _require_string(request, "method")
    payload = request.get("input") or {}
    if not isinstance(payload, Mapping):
        raise CursorSDKError("input must be a JSON object")
    result = dispatch_store_op(store_handler, substore, op, payload)
    if inspect.isawaitable(result):
        result = _resolve_awaitable(result, loop)
    # An unset `output` is a null result (get miss, delete, ...).
    return {"output": result} if result is not None else {}


def _resolve_awaitable(awaitable: Any, loop: asyncio.AbstractEventLoop | None) -> Any:
    """Run an ``async`` substore method's coroutine on the caller's loop.

    Store callbacks are served on the threaded HTTP server, so the coroutine
    is scheduled onto the ``AsyncClient``'s event loop and waited on from the
    request thread.
    """
    if loop is None:
        if inspect.iscoroutine(awaitable):
            awaitable.close()
        raise CursorSDKError(
            "async store handler methods require an AsyncClient / AsyncBridge; "
            "no event loop is available to run the coroutine."
        )

    async def _runner() -> Any:
        return await awaitable

    return asyncio.run_coroutine_threadsafe(_runner(), loop).result()


def _require_string(request: Mapping[str, Any], key: str) -> str:
    value = request.get(key)
    if not isinstance(value, str) or not value:
        raise CursorSDKError(f"{key} is required")
    return value


def store_callback_bridge_argv(endpoint: StoreCallbackEndpoint) -> list[str]:
    return [
        "--store-callback-url",
        endpoint.url,
        "--store-callback-auth-token",
        endpoint.auth_token,
    ]


def local_store_bridge_argv(
    local: LocalAgentOptions | Mapping[str, Any] | None,
) -> list[str]:
    """argv binding the bridge's default local store for every operation.

    Mirrors the TS SDK's ``configureCursorSdk({ local: { store } })`` so
    create / list / get / resume all use the same store. Returns ``[]`` when no
    store is configured (the bridge then uses its default SQLite store).
    """
    store = _store_config(local_options_wire(local))
    if store is None or not store.get("type"):
        return []
    return ["--local-store", json.dumps(dict(store))]


# Store types whose substore operations are delegated to the host. Everything
# else ("sqlite"/default, "jsonl") runs entirely inside the bridge.
_STORE_TYPES_WITH_CALLBACKS = frozenset({"custom"})


def local_options_wire(
    local: LocalAgentOptions | Mapping[str, Any] | None,
) -> Mapping[str, Any] | None:
    if local is None:
        return None
    if isinstance(local, LocalAgentOptions):
        return local.to_json()
    return _normalize_local_options(dict(local))


def _store_config(local: Mapping[str, Any] | None) -> Mapping[str, Any] | None:
    if not isinstance(local, Mapping):
        return None
    store = local.get("store")
    return store if isinstance(store, Mapping) else None


def needs_store_callback_server(local: Mapping[str, Any] | None) -> bool:
    """True when ``local.store`` delegates substore operations to the host.

    Host callbacks are needed for ``"custom"`` (a full ``LocalAgentStoreHandler``
    owned by the host). ``"sqlite"`` (the default) and ``"jsonl"`` run entirely
    inside the bridge.
    """
    store = _store_config(local)
    if store is None:
        return False
    return str(store.get("type") or "") in _STORE_TYPES_WITH_CALLBACKS


def resolve_store_callback_handler_for_launch(
    *,
    local: LocalAgentOptions | Mapping[str, Any] | None = None,
    store_handler: LocalAgentStoreHandler | None = None,
) -> LocalAgentStoreHandler | None:
    """Return the handler only when ``local.store`` requires host callbacks.

    A ``"custom"`` store is backed by the given ``LocalAgentStoreHandler``.
    """
    if not needs_store_callback_server(local_options_wire(local)):
        if store_handler is not None:
            raise ConfigurationError(
                'store_handler is only for local.store type "custom". Omit it '
                'for "sqlite" (the default) and "jsonl", which do not call back '
                "to the host."
            )
        return None
    if store_handler is None:
        raise ConfigurationError(
            "local.store requires a store_handler (LocalAgentStoreHandler) when "
            "launching the bridge. Pass store_handler with the same local.store "
            "on Client.launch_bridge / Bridge.launch."
        )
    if not is_local_agent_store_handler(store_handler):
        raise ConfigurationError(
            "store_handler must be a LocalAgentStoreHandler implementing "
            "agents/runs/run_events/checkpoints."
        )
    return store_handler


def ensure_store_callback_for_agent_options(
    *,
    bridge_store_callback_enabled: bool,
    bridge_is_sdk_owned: bool,
    options: Mapping[str, Any],
) -> None:
    local = options.get("local")
    if not isinstance(local, Mapping):
        return
    if not needs_store_callback_server(local):
        return
    if bridge_store_callback_enabled:
        return
    if not bridge_is_sdk_owned:
        # Connected to an externally launched bridge: the SDK can't see its
        # store-callback configuration, so defer to the bridge to accept or
        # reject the request rather than failing on a false negative.
        return
    raise ConfigurationError(
        'Agent options use a local.store of type "custom" that calls back to '
        "the host, but the bridge was launched without a store callback server. "
        "Call Client.launch_bridge(..., local=..., store_handler=...) "
        "with matching local.store before create_agent / resume_agent."
    )
